    : "OK - " + state.substring(0, 30);
node.status({fill: blockDischarge ? "yellow" : "green", shape: "dot", text: txt});
return msg;

// Režim nepřítomnosti — snížení teploty když nejsme doma
var config = global.get("fve_config") || {};
var AWAY_TEMP = config.topeni_teplota_nepritomnost || 21;
