var _buyP = 99, _sellP = 99;
for (var _pi = 0; _pi < _planArr.length; _pi++) {
    if (_planArr[_pi].hour === _hour && _planArr[_pi].offset !== undefined) {
        _buyP = parseFloat(_planArr[_pi].priceBuy) || 99;
        _sellP = parseFloat(_planArr[_pi].priceSell) || 99;
