    node.status({fill:"red", shape:"dot", text:_reason + " → ALL OFF"});
    if (stopActions.length > 0) return [stopActions, chgMsg];
    return [null, chgMsg];
}

// Bateriové senzory
// battMinus: kladné = baterie VYBÍJÍ (sensor.nabijeni_baterii_minus, vždy >= 0)
