        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"⚡GRID-CD " + Math.round(gridDraw) + "W → " + actPat + "→" + newT + "f SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    if (batSoc < DRAIN_SOC_PRAH && battCharging < -200 && actPat > 0) {
